// SAME imports...

export default function Admin(){

  // SAME states...
  const [showModal,setShowModal]=useState(false);
  const [selectedAlertId,setSelectedAlertId]=useState(null);
  const [proofImage,setProofImage]=useState(null);

  const openResolveModal=(id)=>{
    setSelectedAlertId(id);
    setShowModal(true);
  }

  const submitResolve=()=>{
    if(!proofImage) return alert("Upload proof");

    navigator.geolocation.getCurrentPosition(pos=>{
      const formData=new FormData();
      formData.append("proof_image",proofImage);
      formData.append("latitude",pos.coords.latitude);
      formData.append("longitude",pos.coords.longitude);

      axios.post(`http://127.0.0.1:8000/api/resolve-api/${selectedAlertId}/`,formData)
      .then(()=>{
        alert("Resolved ✅");
        setShowModal(false);
        setProofImage(null);
        loadAlerts();
      })
      .catch(()=>alert("Verification failed ❌"));
    });
  }

  // TABLE call:
  // replace resolveAlert with openResolveModal

  // ADD modal at bottom:
  {showModal && (
    <Modal submitResolve={submitResolve} setProofImage={setProofImage} close={()=>setShowModal(false)}/>
  )}
}
